INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989536","title":"The Thanos Quest","author":"Джим Старлин","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006177633/140/98a0/Dzhim_Starlin__The_Thanos_Quest.jpg","isbn":"B01BG0IPRC","publisher":"Marvel","pubDate":"2000","language":"","series":"","genres":[],"annotation":"Thanos the Mad Titan has returned! Witness the story that shows how Thanos scoured the cosmos and battled the Elders of the Universe for the mighty and all powerful Infinity Gems? Now for the first time, the adventure is collected in one handy volume! If you''re a fan of cosmic action, then this evergreen collection is a must-have! Softcover, 96 pages, full color.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":4,"review":"","added":9999670,"hdCover":""},{"id":"0989535","title":"Смерть Капитана Марвела","author":"","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003605465/140/0539/sbornik__Smert_Kapitana_Marvela.jpg","isbn":"978-5-04-102826-8","publisher":"Эксмо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"БУДУЧИ ЗАЩИТНИКОМ ВСЕЛЕННОЙ, КАПИТАН МАР-ВЕЛЛ ПОБЕЖДАЛ САМЫХ РАЗНЫХ ВРАГОВ! Но когда герою Крии диагностировали рак, он оказался втянут в битву с противником, которого при всём своём могуществе не мог победить. Поэтому ему и Вселенной, что так его любит, придётся вместе принять неизбежное. Также познакомьтесь с классическими приключениями, начиная с первого появления Мар-Велла и стычки с Нитро, ставшей причиной роковой болезни! Узнайте, как в самый разгар битвы с огромной отравленной безумием Таноса планетой-компьютером Титаном зародилась любовь Мар-Велла и его избранницы Элизиус! Гости сборника: Мстители, Люди Икс, Фантастическая Четвёрка и многие другие!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":4.5,"review":"","added":9999669,"hdCover":""},{"id":"0989534","title":"Колдун. Книга 2","author":"Джим Старлин","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002855927/140/36cf/Dzhim_Starlin__Koldun._Kniga_2.jpg","isbn":"2304-9057","publisher":"Marvel, Ашет Коллекция, Панини Рус","pubDate":"2018","language":"Русский","series":"Marvel. Официальная коллекция комиксов","genres":[],"annotation":"Продолжение истории Колдуна Адама. На этот раз ему придется вступить в сражение с могущественным Звездным Вором и вместе с Мстителями остановить безумного титана Таноса. Дополнительные материалы: галерея обложек.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":3,"review":"","added":9999668,"hdCover":""},{"id":"0989533","title":"Колдун. Книга 1.","author":"Джим Старлин","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002814250/140/62de/Dzhim_Starlin__Koldun._Kniga_1..jpg","isbn":"2304-9057","publisher":"Marvel, Ашет Коллекция, Ашетт Коллекция, Панини Рус","pubDate":"2018","language":"","series":"Marvel. Официальная коллекция комиксов","genres":[],"annotation":"Его имя стало легендой по всей галактике. Колдун Адам, обладатель загадочного камня души и спаситель Контр-Земель. Теперь этот могущественный герой должен положить конец существованию Вселенской церкви истины - зловещей секты, поработившей множество планет. Но, отправляясь в новое космическое путешествие, Колдун узнает шокирующую тайну ее лидера - Магуса. И эта тайна превращает его миссию в битву с собственной душой!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":4,"review":"","added":9999667,"hdCover":""},{"id":"0989532","title":"Мстители Западного побережья. Поиски Вижна","author":"Джон Бирн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005800356/140/6f88/Dzhon_Birn__Mstiteli_Zapadnogo_poberezhya._Poiski_Vizhna.jpg","isbn":"978-5-04-117159-9","publisher":"Комильфо","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Вам выпал шанс своими глазами узреть, как один из самых известных авторов комиксов нашёл новый подход к \"Мстителям Западного побережья\", первым делом вернув в сюжет Вижна! Раскрыты древние тайны человечества! Алая Ведьма делает первый шаг по пути, который приведёт к распаду Мстителей! Первое появление Мстителей Великих озёр и триумфальное возвращение одной из самых значимых легенд Marvel времён Золотого века!  В сборник вошли комиксы \"Мстители Западного побережья\" #42-50 сценариста/художника Джона Бирна.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":4.5,"review":"","added":9999666,"hdCover":""},{"id":"0989531","title":"Мстители. Вижн и Алая Ведьма","author":"Стив Энглхарт,Билл Мэнтло","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005538474/140/95f8/__Mstiteli._Vizhn_i_Alaya_Vedma.jpg","isbn":"978-5-04-117162-9","publisher":"Эксмо, Комильфо","pubDate":"2020","language":"Русский","series":"Герои Marvel (обл)","genres":["Комиксы","манга","графические романы"],"annotation":"Священному союзу Ванды и Вижна уже немало лет. вот только в отличие от обычных браков, эти двое обменялись клятвами не где-нибудь, а в Лимбе. Может ли выйти что-то славное, когда любовь скреплена при столь гротескных обстоятельствах? Конечно же, нет! Удивительных подарков молодые не дождутся — вместо этого им предстоит разгадать тайну времён Золотого века! Среди гостей — лишь узкий круг самых близких людей, Мстители да Нелюди. Никакого праздничного торта, никакого марша Мендельсона и прочих радостей, когда над счастьем молодожёнов зависнет угроза со стороны Дормамму и Мрачного Жнеца. Кроме того, Вижну предстоит встретиться с братьями, а Алой Ведьме узнать, кто же на самом деле её отец. Действительно, сколь странная парочка, столь и удивительные их приключения!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":3.5,"review":"","added":9999665,"hdCover":""},{"id":"0989530","title":"Ultimate Comics Wolverine: Legacies","author":"Каллен Банн,Дэвид Мессина","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002967534/140/05e7/__Ultimate_Comics_Wolverine_Legacies.jpg","isbn":"9780785184300","publisher":"Marvel","pubDate":"2013","language":"Английский","series":"Ultimate Comics Wolverine","genres":[],"annotation":"Jimmy Hudson''s quest to discover the answers about his past begins! What mission was Wolverine on that led to the birth of Jimmy? A story that will rock the Ultimate Universe''s family tree forever!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":3,"review":"","added":9999664,"hdCover":""},{"id":"098952f","title":"Ultimate Comics: Iron Man","author":"Nathan Edmondson","type":"Книга","cover":"https://s1.livelib.ru/boocover/1003227229/140/2a9b/Nathan_Edmondson__Ultimate_Comics_Iron_Man.jpg","isbn":"9780785166177","publisher":"Marvel","pubDate":"2013","language":"Английский","series":"","genres":[],"annotation":"What dark motivation drives reckless Tony Stark to be one of Earth''s greatest heroes? What secret of Tony''s has turned War Machine against him? And who or what is...Ultimate Mandarin?! Be here for the return of Ultimate Iron Man - and experience the Demon in the Armor!  Collecting: Ultimate Comics: Iron Man 1-4","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":3,"review":"","added":9999663,"hdCover":""},{"id":"098952e","title":"Ultimate Comics Hawkeye by Jonathan Hickman","author":"Джонатан Хикман,Рафа Сандовал","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002955134/140/44ca/__Ultimate_Comics_Hawkeye_by_Jonathan_Hickman.jpg","isbn":"9780785162278","publisher":"Marvel","pubDate":"2012","language":"Английский","series":"Ultimate Comics Hawkeye","genres":[],"annotation":"Armed and dangerous, what Hawkeye discovers will revererate across the entire Ultimate Universe. Tasked on a covert and dangerous mission, Hawkeye finds himself in the middle of an international arms race -- but on the brink of obtaining a serum that will change the course of mutant history, has the eagle-eyed hero aimed too high to succeed?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":3,"review":"","added":9999662,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098952d","title":"Ultimate Comics Captain America","author":"Джейсон Аарон,Рон Гарни","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001848538/140/47bf/__Ultimate_Comics_Captain_America.jpg","isbn":"9780785151951","publisher":"Marvel","pubDate":"2011","language":"Английский","series":"Ultimate Comics Captain America","genres":[],"annotation":"Captain America meets his ultimate nemesis: the Captain America of the Vietnam War! As new enemies face off, old secrets from the Super-Soldier project are revealed. From the superstar WOLVERINE: WEAPON X creative team of Jason Aaron and Ron Garney, get ready for a hard-hitting story of one man''s quest to serve his country - and the sacrifices he must make.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":3,"review":"","added":9999661,"hdCover":""},{"id":"098952c","title":"Ultimate Comics X: Origins","author":"Артур Адамс,Jeph Loeb,Peter Steigerwald,Mark Roslan","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001848036/140/e4be/__Ultimate_Comics_X_Origins.jpg","isbn":"9780785141013","publisher":"Marvel Comics","pubDate":"2012","language":"Английский","series":"","genres":[],"annotation":"The world was on the brink of destruction. Countless heroes died. The Fantastic Four have disbanded. The X-Men are gone. Mutants are hunted as criminals. But there is hope - in the form of an unlikely group of young heroes gathered together to save tomorrow. Who, or what, is Ultimate X?  COLLECTING: Ultimate Comics X 1-5","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":4,"review":"","added":9999660,"hdCover":""},{"id":"098952b","title":"Ultimate Comics Doomsday","author":"Брайан Майкл Бендис,Рафа Сандовал","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1001848189/140/fe11/__Ultimate_Comics_Doomsday.jpg","isbn":"9780785147763","publisher":"Marvel","pubDate":"2011","language":"Английский","series":"","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Who is the face of true evil in the Ultimate Universe? What is the biggest secret the world doesn''t know? Join the gathered heroes as they embark on an adventure unlike anything seen in Marvel Comics...and that''s a promise!!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":4,"review":"","added":9999659,"hdCover":""},{"id":"098952a","title":"Ultimate Comics Avengers Vs. New Ultimates: Death of Spider-Man","author":"Марк Миллар,Лейнил Фрэнсис Ю","type":"Книга","cover":"https://s1.livelib.ru/boocover/1001848613/140/e013/__Ultimate_Comics_Avengers_Vs._New_Ultimates_Death_of_SpiderMan.jpg","isbn":"9780785152736","publisher":"Marvel","pubDate":"2012","language":"Английский","series":"","genres":[],"annotation":"IT. IS. ON! The two most powerful super-teams in the Ultimate Universe collide in the brawl of the century! A misunderstanding has brought these two colossal teams to blows, and their battle may just spell the end for the Ultimate world! COLLECTING: ULTIMATE COMICS AVENGERS vs. NEW ULTIMATES 1-6","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":3.5,"review":"","added":9999658,"hdCover":""},{"id":"0989529","title":"Современные Мстители. Блэйд против мстителей","author":"Марк Миллар,Стив Диллон","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005023821/140/31c0/__Sovremennye_Mstiteli._Blejd_protiv_mstitelej.jpg","isbn":"978-5-6043127-3-5","publisher":"Зодиак","pubDate":"2020","language":"Русский","series":"","genres":["Фантастика","Комиксы","манга","графические романы"],"annotation":"Оперативная группа по тайным операциям, Мстители выполняют задания, слишком грязные для публичных “Алтимэйтс”. А что может быть темнее и грязнее, чем организованное вампирское нападение.  Полувампир Блэйд привык бороться с вампирами в одиночку, но кланы осмелели и стали агрессивнее с тех пор, как их возглавил новый уверенный лидер: таинственный вампир в старой броне Железного человека. И пока новый вампирский король превращает всё больше супергероев в сверхмощных кровососов, у Блэйда возникают разногласия со Мстителями. Смогут ли охотник и жертвы сообща остановить кроваво-красную волну?  Содержит серию “Современные Мстители 3” #1-6 под авторством Марка Миллара (“Алтимэйтс”) и Стива Диллона (“Проповедник”, “Росомаха: Истоки”).","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":3.5,"review":"","added":9999657,"hdCover":""},{"id":"0989528","title":"Ultimate Marvel Team-Up Ultimate Collection TPB","author":"Phil Hester,Мэтт Вагнер,Билл Сенкевич,John Totleben,Jim Mahfood,Брайан Майкл Бендис,Майкл Аллред,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000297302/140/6346/__Ultimate_Marvel_TeamUp_Ultimate_Collection_TPB.jpg","isbn":"078512361X","publisher":"Marvel Comics","pubDate":"2006","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Collecting all 16 issues of Ultimate Marvel Team-Up, plus the star-studded Ultimate Spider-Man Super Special! Teenager Peter Parker may just have started out in the crime-fighting game, but there are plenty of heroes and villains already doing their thing. And it doesn''t take long for Spider-Man to encounter these strange new allies and enemies ...  more »- including Wolverine, the Hulk, Iron Man, the Punisher, Daredevil, the Fantastic Four, the Man-Thing, the X-Men, Doctor Strange, the Black Widow, Shang-Chi and more! Take a wild tour through the ever-exciting Ultimate universe, as Eisner Award-winning writer Brian Michael Bendis teams up with the comic industry''s greatest artistic talents! Through the eyes of Peter Parker, Ultimate Marvel Team-Up showcases all the Ultimate heroes. From uncanny mutants to gleaming Avengers to rampaging green brutes, this volume has it all!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":3,"review":"","added":9999656,"hdCover":""},{"id":"0989527","title":"Ultimate Comics Iron Man: Armor Wars","author":"Стив Курт,Уоррен Эллис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002954607/140/9221/__Ultimate_Comics_Iron_Man_Armor_Wars.jpg","isbn":"9780785142508","publisher":"Marvel","pubDate":"2010","language":"Английский","series":"Ultimate Comics Armor Wars","genres":["Комиксы","манга","графические романы"],"annotation":"The Iron Man armor has fallen into the hands of the world''s criminal underground. The Ultimates have disbanded, the world is in ruins and Stark''s money has finally found its limits. And the only way to make sure that criminals don''t use his creation for evil is to hunt them down himself.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":2,"review":"","added":9999655,"hdCover":""},{"id":"0989526","title":"Абсолютная сила","author":"Брайан Майкл Бендис,Джей Майкл Стражински,Грег Ленд,Крис Элиопулос,Justin Ponsor,Jay Leisten,Кори Пети,Эндрю Кроссли,Мэтт Райан,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000722290/140/61b8/__Absolyutnaya_sila.jpg","isbn":"978-5-414-00192-8","publisher":"Комикс ЛТД","pubDate":"2010","language":"Русский","series":"Золотая коллекция комиксов","genres":["Детские книги","Комиксы","манга","графические романы"],"annotation":"Когда-то этот важный урок пришлось выучить Человеку-Пауку. Сейчас на очереди другой знаменитый герой - Мистер Фантастик! Его необдуманное решение ставит на грань гибели целую планету в другом измерении. Но там тоже есть свои супергерои - могучий Верховный Эскадрон! И он прибыл на Землю, чтобы серьезно разобраться и покарать виновных. Это тот редкий случай, когда самоуверенный Мистер Фантастик вынужден позвать на помощь... всех супергероев Земли! Графическую новеллу \"Абсолютная сила\" создала команда суперзвездных сценаристов Marvel: Брайан Майкл Бендис, Джеф Лоеб и Джей Майкл Стражински.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":3,"review":"","added":9999654,"hdCover":""},{"id":"0989525","title":"Ultimate Iron Man, Vol. 2","author":"Orson Scott Card","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002644904/140/196e/Orson_Scott_Card__Ultimate_Iron_Man_Vol._2.jpg","isbn":"078511856X, 9780785118565","publisher":"Marvel","pubDate":"2009","language":"Английский","series":"","genres":[],"annotation":"The untold origin of Iron Man continues! When last we saw him, young Tony Stark was nearly blown to bits. How much of him survived his initial Iron Man trial run - and where does the young genius go from here?  Collecting: Ultimate Iron Man II 1-5","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":1.5,"review":"","added":9999653,"hdCover":""}]');

