  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989524","title":"Ultimate Iron Man, Vol. 1","author":"Orson Scott Card","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002644903/140/3483/Orson_Scott_Card__Ultimate_Iron_Man_Vol._1.jpg","isbn":"078512151X, 9780785121510","publisher":"Marvel","pubDate":"2006","language":"Английский","series":"","genres":[],"annotation":"International bestseller, four-time Hugo award, two-time Nebula award and World Fantasy Award winner Orson Scott Card (Ender''s Game) comes to the Ultimate Universe. He''s joined by industry legend Andy Kubert (Marvel 1602, Wolverine: Origin) to show the shocking beginning of Ultimate Iron Man! If you thought The Ultimates told you everything you needed to know about Ultimate Iron Man, think again!  Collecting: Ultimate Iron Man 1-5","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":3,"review":"","added":9999652,"hdCover":""},{"id":"0989523","title":"Ultimate Vision","author":"Марк Миллар,Майк Кэри,Джон Ромита-мл.,Брэндон Петерсон","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002952312/140/fec8/__Ultimate_Vision.jpg","isbn":"9780785121732","publisher":"Marvel","pubDate":"2008","language":"Английский","series":"Ultimate Vision","genres":[],"annotation":"The Earth was saved from the Ultimate threat: Gah Lak Tus. But scientist George Tarleton has captured a piece of that awesome entity and plans to reactivate it for his own evil purposes. The only hope for mankind against this mad scheme is the strange alien being called the Vision.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":3,"review":"","added":9999651,"hdCover":""},{"id":"0989522","title":"Ultimate Galactus, Vol. 3: Extinction","author":"Уоррен Эллис,Брэндон Петерсон","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002951376/140/2714/__Ultimate_Galactus_Vol._3_Extinction.jpg","isbn":"9780785114963","publisher":"Marvel","pubDate":"2006","language":"Английский","series":"Ultimate Extinction","genres":[],"annotation":"It''s time for the coming of Gah Lak Tus! And his arrival could mean the end of all life on this planet! Not even the power of S.H.I.E.L.D or the brilliance of Fantastic Four leader Reed Richards seems able to stop its inexorable march to Earth. What role do the Ultimate X-Men have in this drama? And who on Earth is Misty Knight and how does she know the fate of our world may rest with - Ultimate Silver Surfer?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":3,"review":"","added":9999650,"hdCover":""},{"id":"0989521","title":"Ultimate Galactus, Vol. 2: Ultimate Secret","author":"Уоррен Эллис,Стив МакНивен","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002951371/140/aa0b/__Ultimate_Galactus_Vol._2_Ultimate_Secret.jpg","isbn":"","publisher":"Marvel","pubDate":"2005","language":"","series":"Ultimate X-Men","genres":[],"annotation":"A hidden alien race is trying desperately to keep Man from reaching the stars and Phillip Lawson will use all his considerable power to stop it...the power of Captain Mahr Vehl! Also, the Ultimates and the Ultimate Fantastic Four infiltrate the alien mothership to learn who or what Gah Lak Tus is! Age Rating: 12+","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":3,"review":"","added":9999649,"hdCover":""},{"id":"0989520","title":"Ultimate Galactus Vol. 1: Nightmare","author":"Уоррен Эллис,Стив Эптинг,Тревор Хершин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000298298/140/93bf/__Ultimate_Galactus_Vol._1_Nightmare.jpg","isbn":"9780785114970, 0785114971","publisher":"Marvel","pubDate":"2005","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Superstar Warren Ellis teams with hot newcomer Trevor Hairsine (Ultimate Six) to tell a story of international intrigue that shakes every Ultimate book to its core! As world communications systems break down, the source of the anomaly is revealed as Tunguska, Russia. Nick Fury of S.H.I.E.L.D. leads a force comprised of Captain America, Black Widow, and Sam Wilson to investigate, while, simultaneously, Charles Xavier of the X-Men dispatches his own team consisting of Jean Grey, Wolverine, and Colossus. And what they discover there - and what happens next - defies belief!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":4,"review":"","added":9999648,"hdCover":""},{"id":"098951f","title":"Ultimate Elektra: Devil''s Due","author":"Mike Carey","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002644886/140/139e/Mike_Carey__Ultimate_Elektra_Devil039s_Due.jpg","isbn":"9780785115045","publisher":"Marvel","pubDate":"2005","language":"Английский","series":"","genres":[],"annotation":"Matt Murdock - desperate to see Elektra Natchios again - makes an attempt to contact this mysterious young woman, putting himself squarely in the crosshairs of the biggest crime boss in New York City! Award-winning writer Mike Carey and original Ultimate Daredevil & Elektra artist Salvador Larroca team up for the blockbuster follow-up to the smash-first series!  Collecting Ultimate Elektra 1-5","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":4,"review":"","added":9999647,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"098951e","title":"Люди Икс против команды \"Алтимейтс\". Война Супергероев","author":"Марк Миллар,Крис Бачало","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000850127/140/777e/__Lyudi_Iks_protiv_komandy_quotAltimejtsquot._Vojna_Supergeroev.jpg","isbn":"978-5-414-00282-6","publisher":"Комикс ЛТД","pubDate":"2010","language":"Русский","series":"Избранные сюжеты","genres":["Комиксы","манга","графические романы"],"annotation":"Капитан Америка, Тор, Железный Человек, Соколиный Глаз, Вдова... Вместе они - команда супергероев \"Алтимейтс\" под руководством знаменитого генерала Ника Фьюри! Внезапно Фьюри дает \"Алтимейтс\" задание... найти и уничтожить команду \"Люди Икс\"! Неужели Циклоп, Росомаха, Феникс и другие герои-мутанты изменили своим принципам, став злодеями? И какую роль в этом сыграл самый опасный террорист планеты Магнето? Все прояснит эпическая битва между Людьми Икс и командой \"Алтимейтс\" - первая в истории комиксов!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":3,"review":"","added":9999646,"hdCover":""},{"id":"098951d","title":"Ultimate Adventures: One Tin Soldier","author":"Рон Зиммерман","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1000149678/140/2c25/Ron_Zimmerman__Ultimate_Adventures_One_Tin_Soldier.jpg","isbn":"0785110437","publisher":"Marvel","pubDate":"2005","language":"Английский","series":"","genres":["Детские книги","Комиксы","манга","графические романы"],"annotation":"Book DescriptionAn aging orphan receives his fondest wish and is adopted by the wealthiest man in town... who also happens to be the costumed adventurer known as Hawk-Owl, the Midnight Avenger, Chicago''s crime-fighting scourge! If you ever wondered","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":4,"review":"","added":9999645,"hdCover":""},{"id":"098951c","title":"Ultimate Hulk Annual #1","author":"Джеф Лоэб","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006147819/140/6423/Dzhef_Loeb__Ultimate_Hulk_Annual_1.jpg","isbn":"","publisher":"Marvel","pubDate":"2008","language":"","series":"","genres":[],"annotation":"It''s the Ultimate Road Trip of the Year! The HULK and Zarda - a.k.a. Power Princess from the Squadron Supreme - team-up for the most wild cross-country smash-and-grab you can imagine! Guest-starring Captain America! Join the red-hot team of Jeph Loeb (HULK) and Marko Djurdjevic (THOR) as the mayhem breaks out as only it can in the Ultimate Universe!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":3,"review":"","added":9999644,"hdCover":""},{"id":"098951b","title":"Ultimate Human","author":"Уоррен Эллис","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006147807/140/74e9/Uorren_Ellis__Ultimate_Human.jpg","isbn":"978-0785129172","publisher":"Marvel","pubDate":"2008","language":"","series":"","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":2,"review":"","added":9999643,"hdCover":""},{"id":"098951a","title":"Ultimate Origins","author":"Брайан Майкл Бендис","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002954603/140/eb3f/Brajan_Majkl_Bendis__Ultimate_Origins.jpg","isbn":"9780785136576","publisher":"Marvel","pubDate":"2008","language":"Английский","series":"Utimate Origins","genres":[],"annotation":"This is it! The story that finally reveals the conspiracies behind the entire Ultimate Universe! Now it''s time to discover the jaw-dropping secrets that men have fought and died to protect...how heroes such as Captain America, Nick Fury and Wolverine have more in common than codenames and costumes.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":2.5,"review":"","added":9999642,"hdCover":""},{"id":"0989519","title":"Современные Росомаха против Халка","author":"Дэймон Линделоф, Лейнил Франсис Йю","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002803074/140/c668/Dejmon_Lindelof_Lejnil_Fransis_Jyu__Sovremennye_Rosomaha_protiv_Halka.jpg","isbn":"9785604005873","publisher":"Зодиак","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Начинается великая битва, который не видывала современная вселенная, между неудержимым Халком и бессмертным Росомахой!  Глава ЩИТа Ник Фьюри считал, что с альтер-эго Брюса Баннера, Халком, покончено раз и навсегда. Но груда зелёных и озверевших мышц сеет хаос по всему земному шару. У Фьюри есть огромное количество оперативников, однако только один человек может выполнить задачу, как нужно - Росомаха!  Со своими острыми, как бритва, когтями, крепчайшими адамантиевыми костями и способностью к исцелению от таких ран, от которых любой другой давно бы помер, Логан - идеальный соперник для Халка. Однако уже при первой встрече Халк показал ему, что такое грубая сила, разорвав Росомаху пополам!  Выживет ли кто-нибудь в этой схватке? А если и выживет, останется ли он таким же, как раньше?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-06","rating":4,"review":"","added":9999641,"hdCover":""},{"id":"0989518","title":"Ultimate Comics New Ultimates: Thor Reborn","author":"Джеф Лоэб","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006135585/140/ddf4/Dzhef_Loeb__Ultimate_Comics_New_Ultimates_Thor_Reborn.jpg","isbn":"978-0785139942","publisher":"Marvel","pubDate":"2011","language":"","series":"","genres":[],"annotation":"If only a few super heroes survived the Ultimatum - who is left to become the next super powered team to be reckoned with? The NEW Ultimates! With Thor gone, Loki takes his revenge unleashing the worst of Asgard on Earth. Iron Man must gather the heroes for their biggest Ultimates adventure yet. But who has made the final cut? And who can''t be trusted? The Ultimates face evil once again and you''ll never guess the new enemies they''ll find...or should we say old friends?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-05","rating":4,"review":"","added":9999640,"hdCover":""}]');

