FROM json_each('[{"id":"0989517","title":"Ultimates 3: Who Killed the Scarlet Witch?","author":"Joe Madureira,Джеф Лоэб,Кристиан Лихтнер","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002954600/140/f23c/__Ultimates_3_Who_Killed_the_Scarlet_Witch.jpg","isbn":"9780785122692","publisher":"Marvel Comics","pubDate":"2009","language":"Английский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"After going through the tumultuous events of the past two volumes, a terrible secret is about to tear them apart and bring about a murder at the mansion! One of Earth''s greatest heroes will die, and there''ll be plenty of suspects! New Members! New Adventures! And New Secrets! All this and Ultimate Venom, too!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-05","rating":3,"review":"","added":9999639,"hdCover":""},{"id":"0989516","title":"The Ultimates 2: Ultimate Collection","author":"Марк Миллар","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006098082/140/24d6/Mark_Millar__The_Ultimates_2_Ultimate_Collection.jpg","isbn":"978-0785149163","publisher":"Marvel","pubDate":"2010","language":"","series":"Marvel Ultimate","genres":[],"annotation":"It''s been one year since they stopped an alien invasion, and now there are new members, new costumes and new villains for the Ultimates! Who''s getting married? Who''s divorced? Who''s gone nuts since we last saw them? See Ultimate Hulk and the secret origin of Ultimate Thor!  Tony and Natasha are on the eve of their wedding... but when Nick Fury makes his move against the mysterious traitor that''s been plaguing the team, the team will never be the same! Also, Captain America and Wasp hit a serious snag in their relationship...is this the end for the Ultimate Universe''s hottest couple? Is this the beginning of the end for the Ultimates?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-05","rating":3.5,"review":"","added":9999638,"hdCover":""},{"id":"0989515","title":"Современные Мстители. Команда Алтимэйтс","author":"Марк Миллар","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006095496/140/156e/Mark_Millar__Sovremennye_Mstiteli._Komanda_Altimejts.jpg","isbn":"978-5-6043127-5-9","publisher":"Зодиак","pubDate":"2020","language":"","series":"Marvel Ultimates","genres":[],"annotation":"Человек-Паук и Зелёный Гоблин. Люди Икс и Магнето. Странные, наделённые колоссальным могуществом создания, возникают из ниоткуда, бросают вызов привычному порядку вещей, до смерти пугают простых обывателей. Ник Фьюри собирает спонсируемую правительством команду супергероев, которая включает в себя Капитана Америка, Железного Человека, Тора, Чёрную Вдову, Соколиного Глаза, учёного Хэнка Пима и Брюса Баннера, Осу, Ртуть и Алую Ведьму. Маленький, но смертоносный отряд под названием «Алтимэйтс» собран, чтобы защитить всех нас от надвигающейся новой угрозы роду человеческому!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-05","rating":4,"review":"","added":9999637,"hdCover":""},{"id":"0989514","title":"Современный Человек-Паук. Том 3","author":"Брайан Майкл Бендис,Марк Багли,Стюарт Иммонен,Сара Пиккели,Дэвид Маркез,Брайан Майкл Бэндис,показать всех","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005449467/140/3411/__Sovremennyj_ChelovekPauk._Tom_3.jpg","isbn":"978-5-6043127-4-2","publisher":"Зодиак","pubDate":"2020","language":"Русский","series":"Современный Человек-Паук","genres":[],"annotation":"Майлз Моралес встречается с худшим врагом своего предшественника - Зелёным гоблином, человеком, убившим Питера Паркера! Но мёртв ли Питер на самом деле? События развиваются удивительным образом: Паучок сталкивается с Паучком - и только один продолжит супергеройские будни! Также в сборнике встреча с Гидрой\" и прелюдия к одному из главных событий Вселенной Marvel - Секретным войнам!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-05","rating":4,"review":"","added":9999636,"hdCover":""},{"id":"0989513","title":"Bone Volume 9: Crown of Horns","author":"Jeff Smith","type":"Книга","cover":"https://s1.livelib.ru/boocover/1000661730/140/1aa6/Jeff_Smith__Bone_Volume_9_Crown_of_Horns.jpg","isbn":"1888963166","publisher":"Graphix","pubDate":"2009","language":"Русский","series":"Bone","genres":[],"annotation":"Trapped in a dungeon while the fate of the Valley is decided by two raging armies, Thorn is haunted by the dangerous and mysterious object of power known as the Crown of Horns. Guarded by dragons, the Crown of Horns is the only thing that can stop the Locust and end the war… but how, and at what price? Fone Bone believes he knows the answer, and he must decide where his heart truly lies…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-05","rating":4.5,"review":"","added":9999635,"hdCover":""},{"id":"0989512","title":"На передовой Гражданской войны","author":"Пол Дженкинс","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003354013/140/46ed/Pol_Dzhenkins__Na_peredovoj_Grazhdanskoj_vojny.jpg","isbn":"978-5-04-107447-0","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Репортёры Бен Урих и Салли Флойд намерены раскрыть тайную правду, что скрывается в сердце гражданской войны супергероев. Но сделать это можно, лишь выйдя на передовую… А это крайне опасное место. Через интервью с героями, злодеями, чиновниками и важными игроками по обе стороны Акта Салли и Бен становятся всё ближе к тому, чтобы приподнять завесу тайны и узнать, каков истинный мотив этой войны — но о некоторых секретах лучше никогда не рассказывать. А также: Спидбол стал врагом общества номер один. Его посадили в тюрьму и обвинили в Стэмфордской катастрофе, положившей начало войне. Пытаясь защитить себя, он вскоре понимает, что ему предстоит упасть ещё ниже, чем он полагал — и эта дорога к исправлению приведёт его в очень тёмное место.  В сборник вошли комиксы \"Гражданская война\" #1–11, написанные Полом Дженкинсом и проиллюстрированные Рамоном Бахсом, Стивом Либером, Ли Уиксом и другими.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-05","rating":3.5,"review":"","added":9999634,"hdCover":""},{"id":"0989511","title":"Росомаха. Гражданская война","author":"Марк Гуггенхайм","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003265195/140/a3f3/Mark_Guggenhajm__Rosomaha._Grazhdanskaya_vojna.jpg","isbn":"978-5-04-106809-7","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"После трагедии в Стэмфорде Логан решает взять на себя миссию по устранению её виновника. Однако, начав свою охоту, он обнаруживает, что у его добычи есть и другие преследователи — таинственная троица, чья личность и неоднозначная миссия многих повергнут в шок! Логан сбит с толку появлением этих ребят, но это он ещё не видел, кто отдаёт им приказы! В сборник вошли комиксы \"Росомаха\" #42–48, написанные Марком Гуггенхаймом и проиллюстрированные Умберто Рамосом.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-05","rating":3.5,"review":"","added":9999633,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"0989510","title":"Мисс Марвел. Гражданская война","author":"Брайан Рид,Майк Вайринго,Руслан Хубиев,Роберт Де Ла Торре","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003624493/140/77d6/__Miss_Marvel._Grazhdanskaya_vojna.jpg","isbn":"978-5-04-108427-1","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Комиксы Marvel. Гражданская война","genres":["Комиксы","манга","графические романы"],"annotation":"Гражданская война расколола общество супергероев, и Кэрол Дэнверс вынуждена содействовать осуществлению нового Акта о регистрации сверхлюдей, дабы избежать заключения. Кэрол сражается с бывшими союзниками Саваном и Арахной, защищая закон, с которым, возможно, даже не согласна, но сможет ли она разлучить семью, делая то, что считает правильным? А также: Мисс Марвел и шельма должны забыть о разногласиях, ведь появилась другая Кэрол, зовущая себя Птицей Войны! И она пытается отомстить Шельме! И наконец: когда мальчик, обладающий способностью превращать сны в реальность, прочтёт вслух автобиографический рассказ Кэрол, Мисс Марвел вновь станет космическим героем по прозвищу Бинар! Кэрол Дэнверс ждёт хаос Гражданской войны… и её собственные скелеты в шкафу!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-05","rating":3,"review":"","added":9999632,"hdCover":""},{"id":"098950f","title":"Путь к Гражданской войне","author":"Брайан Майкл Бендис","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003016869/140/0444/Brajan_Majkl_Bendis__Put_k_Grazhdanskoj_vojne.jpg","isbn":"978-5-04-102843-5","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Сборник, в который вошли комиксы \"Новые Мстители: Иллюминаты\" от Брайана Майкла Бендиса и Алекса Малеева, \"Удивительный Человек-Паук\" #529-531 от Дж. Майкла Стражински, Рона Гарли и Тайлера Киркхама и \"Фантастическая Четвёрка\" #536-537 от того же Стражински и Майка Маккона.  Как связаны все эти комиксы? В них описываются события, которые позже выльются в один из самых драматичных моментов в истории вселенной Marvel. Железный Человек объединит величайшие умы Земли в сообщество Иллюминатов, Питер Паркер и Тони Старк отправятся в Вашингтон, на первое обсуждение Акта о регистрации, а в Фантастическая Четвёрка вступит в бой за молот Тора, неизвестно как оказавшийся в Оклахоме.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-05","rating":4,"review":"","added":9999631,"hdCover":""},{"id":"098950e","title":"Дэдпул. Искусство войны","author":"Питер Дэвид","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002662805/140/b318/Piter_Devid__Dedpul._Iskusstvo_vojny.jpg","isbn":"978-5-91339-562-7","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Книгу «Искусство войны» Сунь Цзы называют сновополагающей работой в области военной стратегии и тактики. Она оказала влияние на военачальников и крупных предпринимателей на сотни лет вперёд. А значит, она стала достоянием общественности, и её совершенно точно может «слизать» Дэдпул!  Но как же он планирует обеспечить своей версии продажи больше, чем у оригинала? Приложит все силы, чтобы к моменту её публикации мир погряз в войне! Но вскоре Дэдпул узнает, что развязать войну гораздо проще, чем ею управлять! И вот, Локи пленил Пула и подготовился к завоеванию Земли! К счастью, Дэдпул разбирается в искусстве войны, верно? (Разбирается, в этом же и есть вся суть. Данный комикс — военное пособие от Дэдпула.) Уничтожит ли Землю война Дэдпула, сделает ли она его самым продаваемым автором — или и то, и другое?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-05","rating":4,"review":"","added":9999630,"hdCover":""},{"id":"098950d","title":"Боун. Том 8. Кладоискатели","author":"Джефф Смит","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003632661/140/40a4/Dzheff_Smit__Boun._Tom_8._Kladoiskateli.jpg","isbn":"978-5-9500670-4-4","publisher":"Рамона","pubDate":"2019","language":"Русский","series":"Боун/ Bone","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-05","rating":4.5,"review":"","added":9999629,"hdCover":""},{"id":"098950c","title":"Attack on Titan: Volume 33","author":"Хадзимэ Исаяма","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005579028/140/9ff2/Hadzime_Isayama__Attack_on_Titan_Volume_33.jpg","isbn":"9781646510269","publisher":"Kodansha Comics","pubDate":"2021","language":"Английский","series":"Attack on Titan","genres":["Боевое фэнтези","Зарубежное фэнтези"],"annotation":"The saga of humanity and the predatory Titans edges closer to its thrilling conclusions. The mysteries of the Titans are being revealed… who will escape death at the hands of giants and human beings?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-04","rating":4.5,"review":"","added":9999628,"hdCover":""},{"id":"098950b","title":"Атака на титанов. Книга 16","author":"Хадзимэ Исаяма","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005754657/140/8036/Hadzime_Isayama__Ataka_na_titanov._Kniga_16.jpg","isbn":"978-5-389-19137-2","publisher":"Азбука, Азбука-Аттикус","pubDate":"2021","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Эрен и Зик наконец касаются друг друга – и теперь им ничего не мешает воспользоваться силой изначального титана … Казалось бы, это конец для всего эльдийского народа, однако у младшего брата собственные планы: единолично воспользовавшись обретенным могуществом, он освобождает титанов стен. События принимают новый виток, и ни друзья, ни враги Эрена Йегера не знают, чего ожидать дальше…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-04","rating":4.5,"review":"","added":9999627,"hdCover":""},{"id":"098950a","title":"Атака на титанов. Книга 15","author":"Хадзимэ Исаяма","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004696752/140/d839/Hadzime_Isayama__Ataka_na_titanov._Kniga_15.jpg","isbn":"978-5-389-18438-1","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Собираясь проверить в деле страшное оружие, сокрушающее континенты, сторонники Эрена Йегера организуют военный переворот. Главнокомандующий убит, несогласные арестованы. Леви узнает об истинных намерениях братьев Йегеров, но за это знание ему приходится заплатить слишком высокую цену. А тем временем армия Марли готовится штурмовать Сигансину…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-04","rating":4.5,"review":"","added":9999626,"hdCover":""},{"id":"0989509","title":"Атака на титанов. Книга 14","author":"Хадзимэ Исаяма","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003740904/140/ea83/Hadzime_Isayama__Ataka_na_titanov._Kniga_14.jpg","isbn":"978-5-389-17574-7","publisher":"Азбука, Азбука-Аттикус","pubDate":"2020","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Атака на Либерио поставила Парадиз на грань уничтожения – весь мир ополчился против эльдийского острова и готовит сокрушительный контрудар.  А тем временем действия Эрена и Зика становятся все более непредсказуемыми. Братья преследуют собственные цели, которые могут навсегда изменить лицо этого мира…","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2021-04","rating":4.5,"review":"","added":9999625,"hdCover":""}]');
